xsl:template.xsl:text:
				//Funciones tulizadas en la comunicacion entre el formulario y el reporte

var g_ctrlsType = null;

function matias() {
alert(GetValue("x2"));
}

function GetXMLControls() {
	var objXML = document.getElementById("ctrls_info");
	return objXML.value;
}

function SetValue(pName, pValue) {
		var objTemp = document.getElementById(pName);

}

function GetValue(pName) {
	var objHTML;
	var result = "";

	//Obtiene el valor crudo	
	switch (GetType(pName)) {
		case "string":
		case "double":
			objHTML = document.getElementById(pName);
			result = objHTML.value;
			break;
	}

	//Retorna el tipo correcto
	switch (GetType(pName)) {
		case "string":
			break;

		case "double":
			objHTML = document.getElementById(pName);
			result = str2number(objHTML.value);
			break;
	}

	return result;
}

function GetValue_Box(pName) {
		var objTemp = document.getElementById(pName);
}

//Retorna el tipo de dato de un control
function GetType(pName) {
		var Result = "";

		if (!g_ctrlsType) {
			g_ctrlsType = new Array();
			var xmlCtrlsType = new NomadXML(GetXMLControls());
			var xmlCtrl;
			for (xmlCtrl = xmlCtrlsType.FirstChild(); xmlCtrl != null; xmlCtrl = xmlCtrl.Next()) {
				g_ctrlsType[xmlCtrl.GetAttr("name")] = xmlCtrl.GetAttr("type");
			}
		}


		if (g_ctrlsType[pName]) {
			Result = g_ctrlsType[pName];
		}

		return Result; 
}







function NmdOnChange(pObj) {
	if (pObj.value == "") return;

	var objHTML;

	//Valida el valor segun el tipo correcto
	switch (GetType(pObj.name)) {
		case "string":
			break;

		case "double":
			objHTML = document.getElementById(pObj.name);
			pObj.value = str2number(objHTML.value);
			break;
	}

}

















function number2str(inNumber) {
	return inNumber.toString();
}

function str2number(inSTR) {
	return parseFloat(inSTR);
}

		//Scripts de los controles

function clsCtrlString(pHTMLObj) {

	this.Name = pHTMLObj.id;
	this.Value = pHTMLObj.value;
	this.Enabled = !pHTMLObj.disabled;
	this.Mandatory = pHTMLObj.getAttribute("nmd-mandatory") == "1";

	this.SetValue = function(pValue) {
		if(typeof(pValue) == "string") {
			this.Value = pValue; 
			nmdSetTypedValue(this.Name, pValue);
		} else {
			alert("No se puede asignar el valor '" + pValue + "' al control '" + this.Name + "' no es una cadena.");
		}
	}

	this.SetEnabled = function(pValue) {
		this.Enabled = pValue; 
		nmdSetEnabled(this.Name, pValue);
	}
}

function clsCtrlDouble(pHTMLObj) {

	this.Name = pHTMLObj.id;
	this.Value = pHTMLObj.value;
	this.Enabled = !pHTMLObj.disabled;
	this.Mandatory = pHTMLObj.getAttribute("nmd-mandatory") == "1";

	this.SetValue = function(pValue) {
		if(typeof(pValue) == "number") {
			this.Value = pValue; 
			nmdSetTypedValue(this.Name, pValue);
		} else {
			alert("No se puede asignar el valor '" + pValue + "' al control '" + this.Name + "' no es número.");
		}
	}

	this.SetEnabled = function(pValue) {
		this.Enabled = pValue; 
		nmdSetEnabled(this.Name, pValue);
	}
}

function clsCtrlDate(pHTMLObj) {

	this.Name = pHTMLObj.id;
	this.Value = pHTMLObj.value;
	this.Enabled = !pHTMLObj.disabled;
	this.Mandatory = pHTMLObj.getAttribute("nmd-mandatory") == "1";

	this.SetValue = function(pValue) {
		if(typeof(pValue) == "object") {
			this.Value = pValue; 
			nmdSetTypedValue(this.Name, pValue);
		} else {
			alert("No se puede asignar el valor '" + pValue + "' al control '" + this.Name + "' no es fecha.");
		}
	}

	this.SetEnabled = function(pValue) {
		this.Enabled = pValue; 
		nmdSetEnabled(this.Name, pValue);
	}
}


//Retorna un control
var g_Ctrls = new Array();
function Ctrl(pName) {
	var objResult;

	//Lo busca en el array de objetos
	objResult = g_Ctrls[pName];
	if (objResult) return objResult;

	objResult = document.getElementById(pName);
	if (pName) {
		//Determina de que tipo debe ser el control
		switch (nmdTypeOf(pName)) {
			case "string":    objResult = new clsCtrlString(objResult);   break;
			case "date":      objResult = new clsCtrlDate(objResult);     break;
			case "double":    objResult = new clsCtrlDouble(objResult);   break;
		}			
		g_Ctrls[pName] = objResult;
	}

	return objResult;

}

