			//scripts de FUNCIONAMIENTO ----------------------------------------------------

function nmdPageReady() {
	window.setTimeout("nmdPageResize();", 50);
}

function nmdPageResize() {
	var objTD = document.getElementById("centerTD");
	var objDIV = document.getElementById("centerDIV");

	//Setea el tamano final
	objDIV.style.height = objTD.offsetHeight + "px";
	objDIV.style.width = objTD.offsetWidth + "px";

	//Continua con la ejecucion
	nmdPageLoad();
}

function ButChangeStyle(pObj, pNewStyle) {
	if (pObj?false:true) return;

	try {
		switch(pNewStyle) {
			case "OVER":
				pObj.className = Replace(pObj.className, '_n', '_o');
				if (g_rmode == "DES") {
					pObj.ostyle = pObj.style.backgroundImage;
					pObj.style.backgroundImage = "url(Skins/_Default/Images/Workflow/gear.gif)";
				}
				break;

			case "NORMAL":
				pObj.className = Replace(pObj.className, '_o', '_n');
				if (g_rmode == "DES") {
					pObj.style.backgroundImage = pObj.ostyle;
				}


				break;

			case "DISABLED":
				pObj.disabled = true;
				pObj.className = Replace(pObj.className, '_o', '_d');
				pObj.className = Replace(pObj.className, '_n', '_d');
				break;

			case "ENABLED":
				pObj.disabled = false;
				pObj.className = Replace(pObj.className, '_d', '_n');
				pObj.className = Replace(pObj.className, '_o', '_n');
				break;
		}

	} catch (e) {}

}

function ChangeStyle(obj, pNewStyle) {
	if (obj?false:true) return;

	try {
		switch(pNewStyle) {
			case "OVER":
				obj.className = Replace(obj.className, '_n', '_o');
				break;

			case "NORMAL":
				obj.className = Replace(obj.className, '_o', '_n');
				break;

			case "DISABLED":
				obj.disabled = true;
				obj.className = Replace(obj.className, '_o', '_d');
				obj.className = Replace(obj.className, '_n', '_d');
				break;

			case "ENABLED":
				obj.disabled = false;
				obj.className = Replace(obj.className, '_d', '_n');
				obj.className = Replace(obj.className, '_o', '_n');
				break;
		}

	} catch (e) {}

}

function SButtonChangeStyle(pObj, pNewStyle) {

	if (pObj ? false:true) return;

	try {

		switch(pNewStyle) {
			case "OVER":
				if (!pObj.disabled) {
					pObj.childNodes.item(0).src = Replace(pObj.childNodes.item(0).src, '_n.gif', '_o.gif');
				}
			break;

			case "NORMAL":
				if (!pObj.disabled) {
					pObj.childNodes.item(0).src = Replace(pObj.childNodes.item(0).src, '_o.gif', '_n.gif');
				}
			break;

			case "DISABLED":
				pObj.disabled=true;
				pObj.childNodes.item(0).src = Replace(pObj.childNodes.item(0).src, '_n.gif', '_d.gif');
				pObj.childNodes.item(0).src = Replace(pObj.childNodes.item(0).src, '_o.gif', '_d.gif');
			break;

			case "ENABLED":
				pObj.disabled=false;
				pObj.childNodes.item(0).src = Replace(pObj.childNodes.item(0).src, '_d.gif', '_n.gif');
				pObj.childNodes.item(0).src = Replace(pObj.childNodes.item(0).src, '_o.gif', '_n.gif');
			break;
		}
	} catch (e) {}

}

			var g_rmode = 'DES';

//No borrar. Existe por compatibiliad
function nmdPageLoad() {
}

//scripts utilizados en EDICION DEL FORMULARIO -------------------------------------
function CtrlFocus(pObj, pOver) {
	pObj.childNodes.item(0).childNodes.item(0).style.display = (pOver?"inline":"none");
}

function GroupFocus(pObj, pOver) {
	var objTemp;

	try {
		if (pOver)
			pObj.className = Replace(pObj.className, '_n', '_o');
		else
			pObj.className = Replace(pObj.className, '_o', '_n');


		objTemp = document.getElementById(pObj.id + "_bar");
		objTemp.className = pOver ? "Gear_bar_o" : "Gear_bar_n";

		objTemp = document.getElementById(pObj.id + "_gear");
		objTemp.style.display = pOver ? "inline" : "none";

	} catch (e) {
		alert("Error en GroupFocus: " + e.Description);
	}
}

//Eventos para el onContextMenu -----------------------------------------------------

function MenuCtrlVer(pObj, pEvent) {
	OpenMenu(pObj, "menu_ctrl_ver", pEvent);
}

function MenuCtrlHor(pObj, pEvent) {
	OpenMenu(pObj, "menu_ctrl_hor", pEvent);
}

function MenuForm(pObj, pEvent) {
	OpenMenu(pObj, "menu_form", pEvent);
}

function MenuGroup(pObj, pEvent) {
	OpenMenu(pObj, "menu_MainG", pEvent);
}

function OpenMenu(pObj, pMenuName, pEvent) {
	var xmlParam = new NomadXML("PARAMS");
	var objTA = document.getElementById(pMenuName);

	if (pObj.getAttribute("oi")) xmlParam.SetAttr("ID", pObj.getAttribute("oi"));
	if (pObj.getAttribute("parentoi")) xmlParam.SetAttr("PARENT", pObj.getAttribute("parentoi"));

	parent.OpenMenu(xmlParam.ToString(), objTA.value, pEvent);

}


